const app = require('./app');

const PORT = process.env.PORT || 7995;

app.listen(PORT, () => {
  console.log(`Server listening on http://localhost:${PORT}`);
});

const express = require('express');
const path = require('path');
const cardsRouter = require('./routes/cards');

const app = express();

// Parse JSON bodies
app.use(express.json());

// Serve static files from public/
const publicDir = path.join(__dirname, 'public');
app.use(express.static(publicDir));

// Health check endpoint
app.get('/health', (_req, res) => {
  res.status(200).json({ status: 'ok' });
});

// Cards API
app.use('/api/cards', cardsRouter);

// Basic error handler middleware
app.use((err, _req, res, next) => {
  if (res.headersSent) return next(err);
  const status = err.code === 'VALIDATION_ERROR' ? 400 : err.code === 'NOT_FOUND' ? 404 : 500;
  const payload = { error: err.message || 'Internal Server Error' };
  if (err.code) payload.code = err.code;
  res.status(status).json(payload);
});

module.exports = app;

const express = require('express');
const service = require('../lib/cardsService');

const router = express.Router();

// GET /api/cards
router.get('/', async (_req, res, next) => {
  try {
    const cards = await service.listCards();
    res.json(cards);
  } catch (err) {
    next(err);
  }
});

// POST /api/cards
router.post('/', async (req, res, next) => {
  try {
    const { front, back } = req.body || {};
    const created = await service.createCard({ front, back });
    res.status(201).json(created);
  } catch (err) {
    next(err);
  }
});

// PUT /api/cards/:id
router.put('/:id', async (req, res, next) => {
  try {
    const id = req.params.id;
    const updates = {};
    if ('front' in req.body) updates.front = req.body.front;
    if ('back' in req.body) updates.back = req.body.back;
    const updated = await service.updateCardById(id, updates);
    res.status(200).json(updated);
  } catch (err) {
    next(err);
  }
});

// DELETE /api/cards/:id
router.delete('/:id', async (req, res, next) => {
  try {
    const id = req.params.id;
    await service.deleteCardById(id);
    res.status(200).json({ deleted: true });
  } catch (err) {
    next(err);
  }
});

module.exports = router;

'use strict';

function generateId() {
  return Math.random().toString(36).slice(2, 10) + Date.now().toString(36);
}

function sanitizeString(value) {
  if (typeof value !== 'string') return '';
  return value.trim();
}

function assertNonEmptyString(value, fieldName) {
  if (typeof value !== 'string') {
    const err = new Error(`${fieldName} must be a string`);
    err.code = 'VALIDATION_ERROR';
    throw err;
  }
  const trimmed = value.trim();
  if (trimmed.length === 0) {
    const err = new Error(`${fieldName} must be a non-empty string`);
    err.code = 'VALIDATION_ERROR';
    throw err;
  }
}

function assertStringIfPresent(value, fieldName) {
  if (value === undefined) return;
  assertNonEmptyString(value, fieldName);
}

module.exports = {
  generateId,
  sanitizeString,
  assertNonEmptyString,
  assertStringIfPresent,
};

'use strict';

const fs = require('fs');
const fsp = fs.promises;
const path = require('path');

const defaultPath = path.join(__dirname, '..', 'data', 'cards.json');
const DATA_FILE = process.env.DATA_FILE || defaultPath;

async function ensureDataFile() {
  const dir = path.dirname(DATA_FILE);
  await fsp.mkdir(dir, { recursive: true });
  try {
    await fsp.access(DATA_FILE, fs.constants.F_OK);
  } catch {
    await fsp.writeFile(DATA_FILE, '[]', 'utf8');
  }
}

async function readCards() {
  await ensureDataFile();
  const content = await fsp.readFile(DATA_FILE, 'utf8');
  try {
    const data = JSON.parse(content);
    if (Array.isArray(data)) return data;
    return [];
  } catch {
    return [];
  }
}

async function writeCards(cards) {
  await ensureDataFile();
  const json = JSON.stringify(cards, null, 2);
  await fsp.writeFile(DATA_FILE, json, 'utf8');
}

module.exports = {
  readCards,
  writeCards,
  DATA_FILE,
};

const { readCards, writeCards } = require('./storage');
const { generateId, assertNonEmptyString, sanitizeString, assertStringIfPresent } = require('./flashcard');

async function listCards() {
  return await readCards();
}

async function createCard({ front, back }) {
  assertNonEmptyString(front, 'front');
  assertNonEmptyString(back, 'back');
  const now = new Date().toISOString();
  const card = {
    id: generateId(),
    front: sanitizeString(front),
    back: sanitizeString(back),
    createdAt: now,
    updatedAt: now,
  };
  const cards = await readCards();
  cards.push(card);
  await writeCards(cards);
  return card;
}

async function updateCardById(id, updates) {
  if (!id || typeof id !== 'string') {
    const err = new Error('id is required');
    err.code = 'VALIDATION_ERROR';
    throw err;
  }
  const cards = await readCards();
  const idx = cards.findIndex((c) => c.id === id);
  if (idx === -1) {
    const err = new Error('Card not found');
    err.code = 'NOT_FOUND';
    throw err;
  }
  const card = cards[idx];
  assertStringIfPresent(updates.front, 'front');
  assertStringIfPresent(updates.back, 'back');
  if ('front' in updates) card.front = sanitizeString(updates.front);
  if ('back' in updates) card.back = sanitizeString(updates.back);
  card.updatedAt = new Date().toISOString();
  cards[idx] = card;
  await writeCards(cards);
  return card;
}

async function deleteCardById(id) {
  if (!id || typeof id !== 'string') {
    const err = new Error('id is required');
    err.code = 'VALIDATION_ERROR';
    throw err;
  }
  const cards = await readCards();
  const idx = cards.findIndex((c) => c.id === id);
  if (idx === -1) {
    const err = new Error('Card not found');
    err.code = 'NOT_FOUND';
    throw err;
  }
  cards.splice(idx, 1);
  await writeCards(cards);
  return true;
}

module.exports = {
  listCards,
  createCard,
  updateCardById,
  deleteCardById,
};

document.addEventListener('DOMContentLoaded', () => {
  const listEl = document.getElementById('cardsList');
  const form = document.getElementById('addForm');
  const frontInput = document.getElementById('frontInput');
  const backInput = document.getElementById('backInput');

  const el = (tag, cls) => {
    const n = document.createElement(tag);
    if (cls) n.className = cls;
    return n;
  };

  async function fetchCards() {
    const res = await fetch('/api/cards');
    const data = await res.json();
    return Array.isArray(data) ? data : [];
  }

  function renderCard(card) {
    const li = el('li', 'border border-black p-3 rounded bg-white');

    const front = el('div', 'font-semibold');
    front.textContent = card.front;
    const back = el('div', 'text-black/80');
    back.textContent = card.back;

    const actions = el('div', 'mt-3 flex gap-2');
    const delBtn = el('button', 'px-3 py-1 bg-white text-red-700 border border-black hover:bg-red-50');
    delBtn.textContent = 'Delete';
    delBtn.addEventListener('click', async () => {
      if (!confirm('Delete this card?')) return;
      const res = await fetch(`/api/cards/${card.id}`, { method: 'DELETE' });
      if (res.ok) load();
    });

    const editBtn = el('button', 'px-3 py-1 bg-red-600 text-white border border-black hover:bg-red-700');
    editBtn.textContent = 'Edit';
    editBtn.addEventListener('click', async () => {
      const newFront = prompt('Edit front', card.front);
      if (newFront === null) return;
      const newBack = prompt('Edit back', card.back);
      if (newBack === null) return;
      const res = await fetch(`/api/cards/${card.id}`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ front: newFront, back: newBack }),
      });
      if (res.ok) load();
    });

    actions.append(editBtn, delBtn);
    li.append(front, back, actions);
    return li;
  }

  async function load() {
    const cards = await fetchCards();
    listEl.innerHTML = '';
    cards.forEach((c) => listEl.appendChild(renderCard(c)));
  }

  if (form) {
    form.addEventListener('submit', async (e) => {
      e.preventDefault();
      const front = (frontInput.value || '').trim();
      const back = (backInput.value || '').trim();
      if (!front || !back) return;
      const res = await fetch('/api/cards', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ front, back }),
      });
      if (res.ok) {
        frontInput.value = '';
        backInput.value = '';
        load();
      }
    });
  }

  load();
});

const request = require('supertest');
const path = require('path');
const fs = require('fs');
const os = require('os');

describe('Express base server and frontend', () => {
  let app;
  let tmpDir;
  let dataFile;

  beforeAll(() => {
    tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'cards-'));
    dataFile = path.join(tmpDir, 'cards.json');
    process.env.DATA_FILE = dataFile;
    app = require('../app');
  });

  beforeEach(() => {
    fs.writeFileSync(dataFile, '[]', 'utf8');
  });

  it('GET /health returns 200 with {status:"ok"}', async () => {
    const res = await request(app).get('/health');
    expect(res.status).toBe(200);
    expect(res.body).toEqual({ status: 'ok' });
  });

  it('serves public/index.html at / with Tailwind Play CDN present', async () => {
    const res = await request(app).get('/');
    expect(res.status).toBe(200);
    expect(res.text).toContain('cdn.tailwindcss.com');
    expect(res.text).toContain('<!doctype html>');
  });
});

const request = require('supertest');
const path = require('path');
const fs = require('fs');
const os = require('os');

describe('Flashcards CRUD API', () => {
  let app;
  let tmpDir;
  let dataFile;

  beforeAll(() => {
    tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'cards-api-'));
    dataFile = path.join(tmpDir, 'cards.json');
    process.env.DATA_FILE = dataFile;
    app = require('../app');
  });

  beforeEach(() => {
    fs.writeFileSync(dataFile, '[]', 'utf8');
  });

  it('POST /api/cards creates a card (201)', async () => {
    const res = await request(app).post('/api/cards').send({ front: 'Question', back: 'Answer' });
    expect(res.status).toBe(201);
    expect(res.body).toHaveProperty('id');
    expect(res.body.front).toBe('Question');
    expect(res.body.back).toBe('Answer');
  });

  it('GET /api/cards lists cards', async () => {
    await request(app).post('/api/cards').send({ front: 'Q1', back: 'A1' });
    await request(app).post('/api/cards').send({ front: 'Q2', back: 'A2' });
    const res = await request(app).get('/api/cards');
    expect(res.status).toBe(200);
    expect(Array.isArray(res.body)).toBe(true);
    expect(res.body.length).toBe(2);
  });

  it('PUT /api/cards/:id updates a card (200)', async () => {
    const created = await request(app).post('/api/cards').send({ front: 'Old', back: 'OldB' });
    const id = created.body.id;
    const res = await request(app).put(`/api/cards/${id}`).send({ front: 'New' });
    expect(res.status).toBe(200);
    expect(res.body.front).toBe('New');
    expect(res.body.back).toBe('OldB');
  });

  it('PUT /api/cards/:id with invalid data returns 400', async () => {
    const created = await request(app).post('/api/cards').send({ front: 'A', back: 'B' });
    const id = created.body.id;
    const res = await request(app).put(`/api/cards/${id}`).send({ front: '' });
    expect(res.status).toBe(400);
    expect(res.body).toHaveProperty('error');
  });

  it('PUT /api/cards/:id with missing id returns 404', async () => {
    const res = await request(app).put('/api/cards/does-not-exist').send({ front: 'X' });
    expect(res.status).toBe(404);
  });

  it('DELETE /api/cards/:id removes card (200)', async () => {
    const created = await request(app).post('/api/cards').send({ front: 'ToDel', back: 'B' });
    const id = created.body.id;
    const res = await request(app).delete(`/api/cards/${id}`);
    expect(res.status).toBe(200);
    expect(res.body).toEqual({ deleted: true });
    const list = await request(app).get('/api/cards');
    expect(list.body.find((c) => c.id === id)).toBeUndefined();
  });

  it('DELETE /api/cards/:id non-existent returns 404', async () => {
    const res = await request(app).delete('/api/cards/nope');
    expect(res.status).toBe(404);
  });

  it('POST /api/cards invalid payload returns 400', async () => {
    const res = await request(app).post('/api/cards').send({ front: '', back: '' });
    expect(res.status).toBe(400);
    expect(res.body).toHaveProperty('error');
  });
});
